async function run(agent) {
  await agent.aiInput("左上角矩形", { value: "VF03" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Billing document", { value: "BX00000028" });
  await agent.aiTap("按左上角menu");
  await agent.aiTap("点击新出现的 Billing Document");
  await agent.aiTap("点击新出现的 Issue Output To");
  await agent.aiTap("Output Details 弹窗表格首行左侧的圆形 radio 单选按钮（同一行文本为 YC30 Inv Output Original）");
  await agent.aiTap("Output Details 弹窗底部右下角、Print Options 文字左边的打印预览小图标（打印机形状）");
  await sleep(10000);
  await agent.aiTap("点击 SAP 返回主页");
  await sleep(10000);
  await agent.aiInput("左上角矩形", { value: "VF03" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiInput("Billing document", { value: "BX00000063" });
  await agent.aiKeyboardPress("Enter");
  await agent.aiTap("选择 Display Document Flow");
  await agent.aiTap("选择 Central Finance document");
  await agent.aiTap("点击 Display Document");
  await sleep(10000);
  await agent.aiAssert("验证 Display document 页面显示的 GL accounts 列表 中同时包含2410110000、5010100003、4610360000 GL 账号");
}
